<?php require "vendor/autoload.php"; $app = require_once "bootstrap/app.php"; $kernel = $app->make(Illuminate\Contracts\Console\Kernel::class); $kernel->bootstrap(); $request = Illuminate\Http\Request::create("/api/incidents/1/status", "POST", ["status" => "transporting"]); $request->setUserResolver(function() { return App\Models\User::where("role", "responder")->first(); }); $controller = app(App\Http\Controllers\Api\IncidentApiController::class); $incident = App\Models\Incident::first(); if(!$incident) die("Incident not found\n"); try { $r = $controller->updateStatus($request, $incident); echo "WORKED\n"; } catch (\Exception $e) { echo "EXCEPTION: " . $e->getMessage() . "\n" . $e->getTraceAsString(); }
